package com.ynxweb4.browser;

import android.Manifest;import android.app.*;import android.content.*;import android.content.pm.PackageManager;import android.graphics.Color;import android.net.*;import android.net.http.SslCertificate;import android.net.http.SslError;import android.os.*;import android.provider.Settings;import android.security.keystore.KeyGenParameterSpec;import android.security.keystore.KeyProperties;import android.view.*;import android.webkit.*;import android.widget.*;import org.json.*;import java.io.*;import java.math.BigInteger;import java.nio.charset.StandardCharsets;import java.security.*;import java.security.interfaces.ECPublicKey;import java.security.spec.ECGenParameterSpec;import java.text.*;import java.util.*;

public final class MainActivity extends Activity {
  private static final String PREFS="browser_state_v2",WALLET="wallet_pending";private final List<Tab>tabs=new ArrayList<>();private FrameLayout webHost;private LinearLayout tabStrip;private EditText address;private TextView status;private String localeTag;private int active=-1;private ValueCallback<Uri[]>fileCallback;private final SecureRandom random=new SecureRandom();
  private static final class Tab{String id,url,title;boolean privacy;WebView web;Tab(String id,String url,boolean privacy){this.id=id;this.url=url;this.title=privacy?"Private":"New tab";this.privacy=privacy;}}

  @Override protected void attachBaseContext(Context base){String saved=base.getSharedPreferences(PREFS,MODE_PRIVATE).getString("locale","");String tag=LocaleCatalog.resolve(saved);Locale locale=Locale.forLanguageTag(tag);android.content.res.Configuration config=new android.content.res.Configuration(base.getResources().getConfiguration());config.setLocale(locale);config.setLayoutDirection(locale);super.attachBaseContext(base.createConfigurationContext(config));}
  @Override public void onCreate(Bundle state){super.onCreate(state);localeTag=LocaleCatalog.resolve(getSharedPreferences(PREFS,MODE_PRIVATE).getString("locale",""));buildUi();restoreTabs();handleCallback(getIntent());registerNetwork();if(tabs.isEmpty())openTab("https://search.ynx.invalid",false);else activate(Math.min(getSharedPreferences(PREFS,MODE_PRIVATE).getInt("active",0),tabs.size()-1));}
  private Button button(String text,View.OnClickListener click){Button b=new Button(this);b.setText(text);b.setOnClickListener(click);b.setAllCaps(false);b.setTextColor(Color.rgb(0,47,167));b.setContentDescription(text);return b;}
  private void buildUi(){LinearLayout root=new LinearLayout(this);root.setOrientation(LinearLayout.VERTICAL);root.setBackgroundColor(Color.WHITE);status=new TextView(this);status.setTextColor(Color.DKGRAY);status.setPadding(16,8,16,8);status.setAccessibilityLiveRegion(View.ACCESSIBILITY_LIVE_REGION_POLITE);root.addView(status,new LinearLayout.LayoutParams(-1,-2));HorizontalScrollView scroll=new HorizontalScrollView(this);tabStrip=new LinearLayout(this);tabStrip.setOrientation(LinearLayout.HORIZONTAL);scroll.addView(tabStrip);root.addView(scroll,new LinearLayout.LayoutParams(-1,-2));LinearLayout nav=new LinearLayout(this);nav.setGravity(Gravity.CENTER_VERTICAL);nav.addView(button("←",v->{if(current()!=null&&current().web.canGoBack())current().web.goBack();}));nav.addView(button("→",v->{if(current()!=null&&current().web.canGoForward())current().web.goForward();}));nav.addView(button("↻",v->{if(current()!=null)current().web.reload();}));address=new EditText(this);address.setSingleLine(true);address.setHint("URL / Search");address.setContentDescription("Address or search query");address.setOnEditorActionListener((v,a,e)->{navigate(v.getText().toString());return true;});nav.addView(address,new LinearLayout.LayoutParams(0,-2,1));nav.addView(button("＋",v->openTab("https://search.ynx.invalid",false)));nav.addView(button("◐",v->{explainPrivate();openTab("https://search.ynx.invalid",true);}));root.addView(nav);LinearLayout actions=new LinearLayout(this);actions.setGravity(Gravity.CENTER);actions.addView(button(LocaleCatalog.get(localeTag,"history"),v->showLibrary("history")));actions.addView(button(LocaleCatalog.get(localeTag,"bookmarks"),v->bookmark()));actions.addView(button(LocaleCatalog.get(localeTag,"downloads"),v->showLibrary("downloads")));actions.addView(button(LocaleCatalog.get(localeTag,"wallet"),v->startWallet()));actions.addView(button(LocaleCatalog.get(localeTag,"ai"),v->pageAi()));actions.addView(button(LocaleCatalog.get(localeTag,"settings"),v->settings()));root.addView(actions);webHost=new FrameLayout(this);root.addView(webHost,new LinearLayout.LayoutParams(-1,0,1));setContentView(root);}
  private void openTab(String url,boolean privacy){Tab tab=new Tab(UUID.randomUUID().toString(),url,privacy);tab.web=createWebView(tab);tabs.add(tab);activate(tabs.size()-1);tab.web.loadUrl(normalize(url));persist();}
  private WebView createWebView(Tab tab){WebView web=new WebView(this);WebSettings s=web.getSettings();s.setJavaScriptEnabled(true);s.setDomStorageEnabled(!tab.privacy);s.setDatabaseEnabled(!tab.privacy);s.setAllowFileAccess(false);s.setAllowContentAccess(true);s.setMixedContentMode(WebSettings.MIXED_CONTENT_NEVER_ALLOW);s.setSafeBrowsingEnabled(true);s.setMediaPlaybackRequiresUserGesture(true);if(tab.privacy)s.setCacheMode(WebSettings.LOAD_NO_CACHE);CookieManager.getInstance().setAcceptThirdPartyCookies(web,false);web.setWebViewClient(new Client(tab));web.setWebChromeClient(new Chrome(tab));web.setDownloadListener((url,userAgent,contentDisposition,mime,length)->reviewDownload(tab,url,userAgent,contentDisposition,mime));return web;}
  private void activate(int index){if(index<0||index>=tabs.size())return;active=index;webHost.removeAllViews();webHost.addView(tabs.get(index).web,new FrameLayout.LayoutParams(-1,-1));address.setText(tabs.get(index).url);renderTabs();persist();}
  private void renderTabs(){tabStrip.removeAllViews();for(int i=0;i<tabs.size();i++){int index=i;Tab tab=tabs.get(i);LinearLayout row=new LinearLayout(this);Button select=button((tab.privacy?"◐ ":"")+tab.title,v->activate(index));select.setContentDescription("Open tab "+tab.title);row.addView(select);row.addView(button("×",v->closeTab(index)));tabStrip.addView(row);}}
  private void closeTab(int index){if(index<0||index>=tabs.size())return;Tab tab=tabs.remove(index);if(tab.privacy){tab.web.clearHistory();tab.web.clearCache(true);tab.web.clearFormData();}tab.web.destroy();if(tabs.isEmpty()){active=-1;openTab("https://search.ynx.invalid",false);}else activate(Math.min(index,tabs.size()-1));persist();}
  private Tab current(){return active>=0&&active<tabs.size()?tabs.get(active):null;}
  private String normalize(String input){String value=input.trim();if(value.matches("https?://.*"))return value;if(value.contains(" ")||!value.contains("."))return"https://search.ynx.invalid/?q="+Uri.encode(value);return"https://"+value;}
  private void navigate(String value){Tab tab=current();if(tab!=null)tab.web.loadUrl(normalize(value));}
  private void persist(){try{JSONArray array=new JSONArray();for(Tab tab:tabs)if(!tab.privacy)array.put(new JSONObject().put("id",tab.id).put("url",tab.url).put("title",tab.title));getSharedPreferences(PREFS,MODE_PRIVATE).edit().putString("tabs",array.toString()).putInt("active",Math.max(0,active)).apply();}catch(JSONException ignored){}}
  private void restoreTabs(){try{JSONArray array=new JSONArray(getSharedPreferences(PREFS,MODE_PRIVATE).getString("tabs","[]"));for(int i=0;i<array.length();i++){JSONObject item=array.getJSONObject(i);Tab tab=new Tab(item.getString("id"),item.getString("url"),false);tab.title=item.optString("title","Recovered tab");tab.web=createWebView(tab);tabs.add(tab);tab.web.loadUrl(tab.url);}}catch(JSONException error){getSharedPreferences(PREFS,MODE_PRIVATE).edit().remove("tabs").apply();status.setText("Recovery data was invalid and was reset.");}}
  private void record(String key,JSONObject item){try{SharedPreferences p=getSharedPreferences(PREFS,MODE_PRIVATE);JSONArray a=new JSONArray(p.getString(key,"[]"));JSONArray out=new JSONArray();out.put(item);for(int i=0;i<Math.min(a.length(),499);i++)out.put(a.get(i));p.edit().putString(key,out.toString()).apply();}catch(JSONException ignored){}}
  private void bookmark(){Tab tab=current();if(tab==null)return;try{record("bookmarks",new JSONObject().put("title",tab.title).put("url",tab.url).put("at",System.currentTimeMillis()));status.setText(LocaleCatalog.get(localeTag,"bookmarks")+" · "+tab.title);}catch(JSONException ignored){}}
  private void showLibrary(String key){try{JSONArray a=new JSONArray(getSharedPreferences(PREFS,MODE_PRIVATE).getString(key,"[]"));StringBuilder b=new StringBuilder();if(a.length()==0)b.append("—");for(int i=0;i<Math.min(a.length(),100);i++){JSONObject item=a.getJSONObject(i);b.append(item.optString("title",item.optString("filename","item"))).append("\n").append(item.optString("url","")).append("\n").append(LocaleCatalog.formatDate(localeTag,new Date(item.optLong("at",0)))).append("\n\n");}new AlertDialog.Builder(this).setTitle(LocaleCatalog.get(localeTag,key.equals("history")?"history":"downloads")).setMessage(b.toString()).setPositiveButton("OK",null).show();}catch(JSONException ignored){}}
  private void reviewDownload(Tab tab,String url,String userAgent,String disposition,String mime){String filename=URLUtil.guessFileName(url,disposition,mime);new AlertDialog.Builder(this).setTitle(LocaleCatalog.get(localeTag,"downloads")).setMessage(filename+"\n"+url+"\n\nDownloaded files remain on the device even for private tabs.").setNegativeButton("Cancel",null).setPositiveButton("Download",(d,w)->{DownloadManager.Request request=new DownloadManager.Request(Uri.parse(url));request.setMimeType(mime);request.addRequestHeader("User-Agent",userAgent);request.addRequestHeader("Cookie",CookieManager.getInstance().getCookie(url));request.setNotificationVisibility(DownloadManager.Request.VISIBILITY_VISIBLE_NOTIFY_COMPLETED);request.setDestinationInExternalPublicDir(android.os.Environment.DIRECTORY_DOWNLOADS,filename);long id=((DownloadManager)getSystemService(DOWNLOAD_SERVICE)).enqueue(request);if(!tab.privacy)try{record("downloads",new JSONObject().put("id",id).put("filename",filename).put("url",url).put("at",System.currentTimeMillis()));}catch(JSONException ignored){}}).show();}
  private final class Client extends WebViewClient{private final Tab tab;Client(Tab tab){this.tab=tab;}@Override public boolean shouldOverrideUrlLoading(WebView view,WebResourceRequest request){Uri uri=request.getUrl();if("ynxbrowser".equals(uri.getScheme())){handleCallback(new Intent(Intent.ACTION_VIEW,uri));return true;}if("ynx-wallet".equals(uri.getScheme())||"ynxwallet".equals(uri.getScheme())){reviewSigning(uri);return true;}return false;}@Override public void onPageStarted(WebView view,String url,android.graphics.Bitmap icon){status.setText(LocaleCatalog.get(localeTag,"loading"));}@Override public void onPageFinished(WebView view,String url){tab.url=url;tab.title=view.getTitle()==null?Uri.parse(url).getHost():view.getTitle();if(!tab.privacy)try{record("history",new JSONObject().put("title",tab.title).put("url",url).put("at",System.currentTimeMillis()));}catch(JSONException ignored){}address.setText(url);SslCertificate cert=view.getCertificate();status.setText(url.startsWith("https://")?(cert==null?"HTTPS · certificate details unavailable":"HTTPS · "+cert.getIssuedTo().getCName()):"Not HTTPS · transport is not encrypted");persist();renderTabs();}@Override public void onReceivedSslError(WebView view,SslErrorHandler handler,SslError error){handler.cancel();status.setText("Certificate error — navigation stopped");}@Override public boolean onRenderProcessGone(WebView view,RenderProcessGoneDetail detail){tab.web.destroy();tab.web=createWebView(tab);if(tab==current()){webHost.removeAllViews();webHost.addView(tab.web);}tab.web.loadUrl(tab.url);status.setText("Page process recovered after "+detail.didCrash());return true;}}
  private final class Chrome extends WebChromeClient{private final Tab tab;Chrome(Tab tab){this.tab=tab;}@Override public void onPermissionRequest(PermissionRequest request){runOnUiThread(()->{String origin=request.getOrigin().toString();String[] resources=request.getResources();String key=origin+"|"+String.join(",",resources);String stored=tab.privacy?"ask":getSharedPreferences(PREFS,MODE_PRIVATE).getString("permission:"+key,"ask");if("allow".equals(stored)){request.grant(resources);return;}if("deny".equals(stored)){request.deny();return;}new AlertDialog.Builder(MainActivity.this).setTitle(LocaleCatalog.get(localeTag,"permissions")).setMessage(origin+"\n"+String.join("\n",resources)).setNegativeButton("Deny",(d,w)->{if(!tab.privacy)getSharedPreferences(PREFS,MODE_PRIVATE).edit().putString("permission:"+key,"deny").apply();request.deny();}).setNeutralButton("Allow once",(d,w)->request.grant(resources)).setPositiveButton("Allow",(d,w)->{if(!tab.privacy)getSharedPreferences(PREFS,MODE_PRIVATE).edit().putString("permission:"+key,"allow").apply();request.grant(resources);}).setOnCancelListener(d->request.deny()).show();});}@Override public void onGeolocationPermissionsShowPrompt(String origin,GeolocationPermissions.Callback callback){new AlertDialog.Builder(MainActivity.this).setTitle(LocaleCatalog.get(localeTag,"permissions")).setMessage(origin+"\nLocation").setNegativeButton("Deny",(d,w)->callback.invoke(origin,false,false)).setPositiveButton("Allow once",(d,w)->callback.invoke(origin,true,false)).show();}@Override public boolean onShowFileChooser(WebView view,ValueCallback<Uri[]> callback,FileChooserParams params){if(fileCallback!=null)fileCallback.onReceiveValue(null);fileCallback=callback;startActivityForResult(params.createIntent(),901);return true;}}
  @Override protected void onActivityResult(int requestCode,int resultCode,Intent data){super.onActivityResult(requestCode,resultCode,data);if(requestCode==901&&fileCallback!=null){fileCallback.onReceiveValue(WebChromeClient.FileChooserParams.parseResult(resultCode,data));fileCallback=null;}}
  private void explainPrivate(){new AlertDialog.Builder(this).setTitle(LocaleCatalog.get(localeTag,"private")).setMessage(LocaleCatalog.get(localeTag,"privateBoundary")).setPositiveButton("OK",null).show();}
  private void reviewSigning(Uri request){String chain=request.getQueryParameter("chainId"),from=request.getQueryParameter("from"),to=request.getQueryParameter("to"),amount=request.getQueryParameter("amountYNXT"),fee=request.getQueryParameter("feeYNXT"),memo=request.getQueryParameter("memo"),data=request.getQueryParameter("data");if(!"ynx_6423-1".equals(chain)||from==null||to==null||amount==null||fee==null){status.setText("Signing request rejected: required exact fields or chain missing");return;}String review=LocaleCatalog.get(localeTag,"transactionReview")+"\n\nChain: "+chain+"\nFrom: "+from+"\nTo: "+to+"\nAmount: "+amount+" YNXT\nFee: "+fee+" YNXT\nMemo: "+(memo==null?"—":memo)+"\nContract data: "+(data==null||data.isBlank()?"none":data);new AlertDialog.Builder(this).setTitle("YNXT transaction").setMessage(review).setNegativeButton("Reject",null).setPositiveButton("Review in YNX Wallet",(d,w)->{try{startActivity(new Intent(Intent.ACTION_VIEW,request));}catch(Exception error){status.setText("Wallet unavailable: "+error.getMessage());}}).show();}
  private void settings(){String[] labels=LocaleCatalog.TAGS;new AlertDialog.Builder(this).setTitle(LocaleCatalog.get(localeTag,"settings")).setItems(labels,(d,which)->{getSharedPreferences(PREFS,MODE_PRIVATE).edit().putString("locale",labels[which]).apply();recreate();}).setNeutralButton(LocaleCatalog.get(localeTag,"clear"),(d,w)->clearData()).setNegativeButton("Cancel",null).show();}
  private void clearData(){String[]items={"History","Bookmarks","Site permissions","Cookies and cache","Crash recovery"};boolean[]checked={true,false,true,true,false};new AlertDialog.Builder(this).setTitle(LocaleCatalog.get(localeTag,"clear")).setMultiChoiceItems(items,checked,(d,w,on)->checked[w]=on).setNegativeButton("Cancel",null).setPositiveButton("Clear",(d,w)->{SharedPreferences.Editor e=getSharedPreferences(PREFS,MODE_PRIVATE).edit();if(checked[0])e.remove("history");if(checked[1])e.remove("bookmarks");if(checked[2])for(String key:getSharedPreferences(PREFS,MODE_PRIVATE).getAll().keySet())if(key.startsWith("permission:"))e.remove(key);if(checked[4])e.remove("tabs");e.apply();if(checked[3]){CookieManager.getInstance().removeAllCookies(null);WebStorage.getInstance().deleteAllData();for(Tab tab:tabs)tab.web.clearCache(true);}status.setText("Local browsing data cleared. Downloaded files remain.");}).show();}
  private void pageAi(){Tab tab=current();if(tab==null)return;if(tab.privacy){status.setText("AI is unavailable in private tabs.");return;}tab.web.evaluateJavascript("JSON.stringify((document.body&&document.body.innerText||'').slice(0,50000))",value->{int size=value==null?0:value.length();new AlertDialog.Builder(this).setTitle(LocaleCatalog.get(localeTag,"ai")).setMessage("Authorized current page only\n"+tab.url+"\n"+LocaleCatalog.formatNumber(localeTag,size)+" characters\nNo history, Wallet identity, unrelated tabs, or private content.\nAI output: "+getSharedPreferences(PREFS,MODE_PRIVATE).getString("aiLocale",localeTag)).setNegativeButton("Cancel",null).setPositiveButton("Approve",(d,w)->{if(AppConfig.GATEWAY_URL.isEmpty())status.setText("AI provider unavailable — no Gateway session configured.");else status.setText("Gateway session verification is required before AI transmission.");}).show();});}
  private void startWallet(){new AlertDialog.Builder(this).setTitle(LocaleCatalog.get(localeTag,"wallet")).setMessage(LocaleCatalog.get(localeTag,"walletReview")).setNegativeButton("Cancel",null).setPositiveButton("Open YNX Wallet",(d,w)->{try{String nonce=randomToken(32),key=devicePublicKey();long issued=System.currentTimeMillis(),expiry=issued+300000;JSONObject request=new JSONObject().put("version","1").put("nonce",nonce).put("chainId","ynx_6423-1").put("requestingProduct","browser").put("productClientId","ynx-browser-android").put("bundleId","com.ynxweb4.browser").put("productDeviceAlgorithm","p256-sha256").put("productDeviceKey",key).put("callback","ynxbrowser://com.ynxweb4.browser/auth/callback").put("scopes",new JSONArray().put("account:read").put("browser:wallet-request")).put("purpose","Sign in to YNX Browser").put("issuedAt",iso(issued)).put("expiresAt",iso(expiry));String encoded=Base64.getUrlEncoder().withoutPadding().encodeToString(request.toString().getBytes(StandardCharsets.UTF_8));getSharedPreferences(WALLET,MODE_PRIVATE).edit().putString("nonce",nonce).putLong("expires",expiry).apply();Intent intent=new Intent(Intent.ACTION_VIEW,Uri.parse("ynxwallet://authorize?request="+encoded));startActivity(intent);}catch(Exception error){status.setText("Wallet unavailable: "+error.getMessage());}}).show();}
  private void handleCallback(Intent intent){Uri uri=intent==null?null:intent.getData();if(uri==null)return;if(!"ynxbrowser".equals(uri.getScheme())||!"com.ynxweb4.browser".equals(uri.getHost())||!"/auth/callback".equals(uri.getPath())){status.setText("Wallet callback rejected: route mismatch");return;}try{SharedPreferences p=getSharedPreferences(WALLET,MODE_PRIVATE);if(p.getLong("expires",0)<=System.currentTimeMillis())throw new SecurityException("expired request");String response=uri.getQueryParameter("response");if(response==null)throw new SecurityException("missing response");JSONObject payload=new JSONObject(new String(Base64.getUrlDecoder().decode(response),StandardCharsets.UTF_8));if(!p.getString("nonce","").equals(payload.getString("nonce")))throw new SecurityException("nonce mismatch");if(p.getBoolean("used:"+payload.getString("nonce"),false))throw new SecurityException("replayed response");if(!"ynx_6423-1".equals(payload.getString("chainId"))||!"ynx-browser-android".equals(payload.getString("productClientId"))||!"com.ynxweb4.browser".equals(payload.getString("bundleId")))throw new SecurityException("product binding mismatch");p.edit().putBoolean("used:"+payload.getString("nonce"),true).remove("nonce").apply();status.setText("Wallet response received. Gateway signature and device challenge verification are required; no session created locally.");}catch(Exception error){status.setText("Wallet callback rejected: "+error.getMessage());}}
  private String devicePublicKey()throws Exception{KeyStore store=KeyStore.getInstance("AndroidKeyStore");store.load(null);String alias="ynx_browser_device_p256";if(!store.containsAlias(alias)){KeyPairGenerator generator=KeyPairGenerator.getInstance(KeyProperties.KEY_ALGORITHM_EC,"AndroidKeyStore");generator.initialize(new KeyGenParameterSpec.Builder(alias,KeyProperties.PURPOSE_SIGN|KeyProperties.PURPOSE_VERIFY).setAlgorithmParameterSpec(new ECGenParameterSpec("secp256r1")).setDigests(KeyProperties.DIGEST_SHA256).setUserAuthenticationRequired(false).build());generator.generateKeyPair();}ECPublicKey key=(ECPublicKey)store.getCertificate(alias).getPublicKey();byte[]x=fixed(key.getW().getAffineX(),32),out=new byte[33];out[0]=(byte)(key.getW().getAffineY().testBit(0)?3:2);System.arraycopy(x,0,out,1,32);return Base64.getUrlEncoder().withoutPadding().encodeToString(out);}
  private static byte[]fixed(BigInteger value,int length){byte[]raw=value.toByteArray(),out=new byte[length];System.arraycopy(raw,Math.max(0,raw.length-length),out,Math.max(0,length-raw.length),Math.min(length,raw.length));return out;}
  private String randomToken(int bytes){byte[]value=new byte[bytes];random.nextBytes(value);return Base64.getUrlEncoder().withoutPadding().encodeToString(value);}private String iso(long millis){return new java.text.SimpleDateFormat("yyyy-MM-dd'T'HH:mm:ss.SSS'Z'",Locale.US){{setTimeZone(TimeZone.getTimeZone("UTC"));}}.format(new Date(millis));}
  private void registerNetwork(){ConnectivityManager cm=(ConnectivityManager)getSystemService(CONNECTIVITY_SERVICE);cm.registerDefaultNetworkCallback(new ConnectivityManager.NetworkCallback(){@Override public void onLost(Network network){runOnUiThread(()->status.setText(LocaleCatalog.get(localeTag,"offline")));}@Override public void onAvailable(Network network){runOnUiThread(()->{if(current()!=null)status.setText("Online · "+Uri.parse(current().url).getHost());});}});}
  @Override protected void onNewIntent(Intent intent){super.onNewIntent(intent);setIntent(intent);handleCallback(intent);}@Override protected void onDestroy(){persist();super.onDestroy();}
}
